import "./select.css";

import { Select } from "radix-ui";

import { SelectContext } from "./select.context";
import { selectVariants } from "./select.variants";

export type SelectRootProps = React.ComponentProps<typeof Select.Root>;

export const SelectRoot = (props: SelectRootProps) => {
  const slots = selectVariants();

  return (
    <SelectContext value={{ slots }}>
      <Select.Root {...props} />
    </SelectContext>
  );
};

import { ChevronDown } from "lucide-react";
import { Select } from "radix-ui";
import { cn } from "tailwind-variants";

import { useSelectContext } from "./select.context";

export type SelectTriggerProps = React.ComponentProps<typeof Select.Trigger>;

export const SelectTrigger = ({ children, className, ...props }: SelectTriggerProps) => {
  const { slots } = useSelectContext();

  return (
    <Select.Trigger className={cn(slots.trigger(), className)} {...props}>
      {children}
      <Select.Icon asChild>
        <ChevronDown className="size-4 opacity-50" />
      </Select.Icon>
    </Select.Trigger>
  );
};

import { ChevronDown, ChevronUp } from "lucide-react";
import { Select } from "radix-ui";
import { cn } from "tailwind-variants";

import { useSelectContext } from "./select.context";

export type SelectContentProps = React.ComponentProps<typeof Select.Content>;

export const SelectContent = ({
  children,
  className,
  position = "popper",
  ...props
}: SelectContentProps) => {
  const { slots } = useSelectContext();

  return (
    <Select.Portal>
      <Select.Content className={cn(slots.content(), className)} position={position} {...props}>
        <Select.ScrollUpButton className={slots.scrollButton()}>
          <ChevronUp />
        </Select.ScrollUpButton>
        <Select.Viewport className={slots.viewport()}>{children}</Select.Viewport>
        <Select.ScrollDownButton className={slots.scrollButton()}>
          <ChevronDown />
        </Select.ScrollDownButton>
      </Select.Content>
    </Select.Portal>
  );
};

import { Check } from "lucide-react";
import { Select } from "radix-ui";
import { cn } from "tailwind-variants";

import { useSelectContext } from "./select.context";

export type SelectItemProps = React.ComponentProps<typeof Select.Item>;

export const SelectItem = ({ children, className, ...props }: SelectItemProps) => {
  const { slots } = useSelectContext();

  return (
    <Select.Item className={cn(slots.item(), className)} {...props}>
      <Select.ItemIndicator className={slots.itemIndicator()}>
        <Check />
      </Select.ItemIndicator>
      <Select.ItemText>{children}</Select.ItemText>
    </Select.Item>
  );
};

import { Select } from "radix-ui";
import { cn } from "tailwind-variants";

import { useSelectContext } from "./select.context";

export type SelectLabelProps = React.ComponentProps<typeof Select.Label>;

export const SelectLabel = ({ className, ...props }: SelectLabelProps) => {
  const { slots } = useSelectContext();

  return <Select.Label className={cn(slots.label(), className)} {...props} />;
};

import { Select } from "radix-ui";
import { cn } from "tailwind-variants";

import { useSelectContext } from "./select.context";

export type SelectSeparatorProps = React.ComponentProps<typeof Select.Separator>;

export const SelectSeparator = ({ className, ...props }: SelectSeparatorProps) => {
  const { slots } = useSelectContext();

  return <Select.Separator className={cn(slots.separator(), className)} {...props} />;
};

import { createContext, useContext } from "react";

import { selectVariants } from "./select.variants";

export type SelectContext = {
  slots: ReturnType<typeof selectVariants>;
};

export const SelectContext = createContext<null | SelectContext>(null);

export const useSelectContext = () => {
  const context = useContext(SelectContext);
  if (!context) {
    throw new Error("useSelectContext must be used within a Select");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const selectVariants = tv({
  slots: {
    content: "select__content",
    item: "select__item",
    itemIndicator: "select__item-indicator",
    label: "select__label",
    scrollButton: "select__scroll-button",
    separator: "select__separator",
    trigger: "select__trigger",
    viewport: "select__viewport",
  },
});

export type SelectVariants = VariantProps<typeof selectVariants>;

.select__trigger {
  @apply border-input bg-background flex h-9 w-full items-center justify-between rounded-md border px-3 py-2 text-sm;

  &:hover {
    @apply bg-accent;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &:disabled {
    @apply cursor-not-allowed opacity-50;
  }

  &[data-placeholder] {
    @apply text-muted-foreground;
  }
}

.select__content {
  @apply bg-popover text-popover-foreground relative z-50 max-h-96 min-w-[8rem] overflow-hidden rounded-md border shadow-md;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95;
  }

  &[data-side="bottom"] {
    @apply slide-in-from-top-2;
  }

  &[data-side="left"] {
    @apply slide-in-from-right-2;
  }

  &[data-side="right"] {
    @apply slide-in-from-left-2;
  }

  &[data-side="top"] {
    @apply slide-in-from-bottom-2;
  }

  &[data-position="popper"] {
    .select__viewport {
      @apply h-[var(--radix-select-trigger-height)] w-full min-w-[var(--radix-select-trigger-width)];
    }
  }
}

.select__viewport {
  @apply p-1;
}

.select__item {
  @apply relative flex w-full cursor-default items-center rounded-sm py-1.5 pr-2 pl-8 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-disabled] {
    @apply pointer-events-none opacity-50;
  }
}

.select__item-indicator {
  @apply absolute left-2 flex items-center justify-center;

  & svg {
    @apply size-3.5;
  }
}

.select__label {
  @apply text-muted-foreground px-2 py-1.5 text-xs font-semibold;
}

.select__separator {
  @apply bg-border -mx-1 my-1 h-px;
}

.select__scroll-button {
  @apply flex cursor-default items-center justify-center py-1;

  & svg {
    @apply size-4;
  }
}

import { SelectContent } from "./select-content";
import { SelectItem } from "./select-item";
import { SelectLabel } from "./select-label";
import { SelectRoot } from "./select-root";
import { SelectSeparator } from "./select-separator";
import { SelectTrigger } from "./select-trigger";

export const Select = {
  Content: SelectContent,
  Item: SelectItem,
  Label: SelectLabel,
  Root: SelectRoot,
  Separator: SelectSeparator,
  Trigger: SelectTrigger,
};

export { SelectContent, SelectItem, SelectLabel, SelectRoot, SelectSeparator, SelectTrigger };

export type { SelectContentProps } from "./select-content";

export type { SelectItemProps } from "./select-item";

export type { SelectLabelProps } from "./select-label";
export type { SelectRootProps } from "./select-root";
export type { SelectSeparatorProps } from "./select-separator";
export type { SelectTriggerProps } from "./select-trigger";
export { SelectContext, useSelectContext } from "./select.context";
export { type SelectVariants, selectVariants } from "./select.variants";
